// Compute failure rate per vendor over the last 60 minutes.
// Vendors are inferred from channel:
//   email     -> postmark
//   sms       -> twilio_sms
//   whatsapp  -> twilio_whatsapp
//   voice     -> vapi
//   linkedin  -> linkedin (proxy via outreach_log)
//   video     -> heygen (proxy via outreach_log)
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const emails   = allOf('Email Calls 60m');
const messages = allOf('Messages 60m');
const outreach = allOf('Outreach 60m');

const CHANNEL_TO_VENDOR = {
  email:    'postmark',
  sms:      'twilio_sms',
  whatsapp: 'twilio_whatsapp',
  voice:    'vapi',
  linkedin: 'linkedin',
  video:    'heygen'
};

function isFailure(status, error) {
  const s = (status || '').toLowerCase();
  if (s === 'failed' || s === 'undelivered' || s === 'bounced' || s === 'dropped' || s === 'rejected') return true;
  if (error && String(error).trim().length > 0) return true;
  return false;
}

function isSuccess(status) {
  const s = (status || '').toLowerCase();
  return s === 'sent' || s === 'delivered' || s === 'queued' || s === 'success';
}

const stats = {};
function record(vendor, channel, isFail, errMsg) {
  if (!stats[vendor]) stats[vendor] = { vendor: vendor, channel: channel, total: 0, success: 0, failure: 0, last_error: null };
  stats[vendor].total++;
  if (isFail) {
    stats[vendor].failure++;
    if (errMsg) stats[vendor].last_error = String(errMsg).slice(0, 200);
  } else {
    stats[vendor].success++;
  }
}

emails.forEach(function (e) {
  if (!e) return;
  record('postmark', 'email', isFailure(e.status, null), null);
});
messages.forEach(function (m) {
  if (!m) return;
  const v = CHANNEL_TO_VENDOR[(m.channel || '').toLowerCase()] || 'other';
  record(v, m.channel || 'other', isFailure(m.status, m.error), m.error);
});
outreach.forEach(function (o) {
  if (!o) return;
  const v = CHANNEL_TO_VENDOR[(o.channel || '').toLowerCase()] || 'other';
  record(v, o.channel || 'other', isFailure(o.status, o.error_message), o.error_message);
});

// Build snapshot rows + alert rows for breached thresholds
const FAILURE_RATE_THRESHOLD = 30;
const MIN_CALLS_FOR_ALERT = 10;
const snapshots = [];
const alerts = [];

Object.keys(stats).forEach(function (vendor) {
  const s = stats[vendor];
  const rate = s.total > 0 ? Math.round((s.failure / s.total) * 10000) / 100 : 0;
  const breached = s.total >= MIN_CALLS_FOR_ALERT && rate > FAILURE_RATE_THRESHOLD;
  const circuit = breached ? 'open' : (s.failure > 0 ? 'half_open' : 'closed');

  snapshots.push({
    vendor: vendor,
    channel: s.channel,
    window_minutes: 60,
    call_count: s.total,
    success_count: s.success,
    failure_count: s.failure,
    failure_rate_pct: rate,
    circuit_state: circuit,
    last_error: s.last_error,
    metadata: {}
  });

  if (breached) {
    alerts.push({
      module_name: 'cost_monitoring',
      alert_type: 'vendor_circuit_open',
      severity: rate > 60 ? 'critical' : 'warning',
      title: 'Vendor health degraded: ' + vendor + ' (' + rate + '% failure rate)',
      message: vendor + ' had ' + s.failure + ' failures out of ' + s.total + ' calls in the last 60 min. Failure rate ' + rate + '% exceeds the ' + FAILURE_RATE_THRESHOLD + '% threshold. Last error: ' + (s.last_error || '(no detail)'),
      details: { vendor: vendor, channel: s.channel, stats: s, threshold_pct: FAILURE_RATE_THRESHOLD },
      status: 'open',
      aggregation_key: 'vendor_circuit:' + vendor
    });
  }
});

return { json: {
  measured_at: new Date().toISOString(),
  snapshots: snapshots,
  alerts: alerts,
  has_alerts: alerts.length > 0
} };
